12	export function nextGeneration(cells: Cell[]): Cell[] {
13	  const liveSet = new Set<string>();
14	  for (const [x, y] of cells) {
15	    liveSet.add(key(x, y));
16	  }
17	
18	  const neighborCounts = new Map<string, number>();
19	
20	  for (const [x, y] of cells) {
21	    for (let dx = -1; dx <= 1; dx++) {
22	      for (let dy = -1; dy <= 1; dy++) {
23	        if (dx === 0 && dy === 0) continue;
24	        const nKey = key(x + dx, y + dy);
25	        neighborCounts.set(nKey, (neighborCounts.get(nKey) ?? 0) + 1);
26	      }
27	    }
28	  }
29	
30	  const result: Cell[] = [];
31	
32	  for (const [k, count] of neighborCounts) {
33	    const isAlive = liveSet.has(k);
34	    if (isAlive && (count === 2 || count === 3)) {
35	      result.push(parseKey(k));
36	    } else if (!isAlive && count === 3) {
37	      result.push(parseKey(k));
38	    }
39	  }
40	
41	  for (const [x, y] of cells) {
42	    const k = key(x, y);
43	    if (!neighborCounts.has(k)) {
44	      // live cell with 0 neighbors — dies, do nothing
45	    }
46	  }
47	
48	  return result;
49	}
